#include<bits/stdc++.h>
using namespace std;
long long a[100010],b[100010],c[100010],pos[100010];
long long tot,mod[100010],val[100010],p[100010];
void fenjie(long long &a,long long b,int id)
{
    long long v=1;
    while(a%p[id]==0)
    {
        a/=p[id];
        v*=p[id];
    }
    if(v>mod[id])
    {
        mod[id]=v;
        val[id]=b%v;
    }
}
long long exgcd(long long a,long long b,long long &x,long long &y)
{
    if(b==0)
    {
        x=1;
        y=0;
        return a;
    }
    long long g=exgcd(b,a%b,x,y);
    long long tx=x;
    x=y;
    y=tx-(a/b)*y;
    return g;
}
bool vis[101];
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        int x;
        scanf("%d",&x);
        pos[x]=i;
    }
    int j=0;
    for(int i=1;i<=n;i++)
    {
        int cnt=0;
        while(j!=pos[i])
        {
            j++;
            if(j==n+1)
            {
                j=1;
            }
            if(!vis[j])
            {
                cnt++;
            }
        }
        vis[pos[i]]=true;
        c[i]=cnt;
    }
    for(int i=1;i<=n;i++)
    {
        long long b=c[i],a=n+1-i;
        b%=a;
        for(int j=1;j<=tot;j++)
        {
            if(a%p[j]==0)
            {
                fenjie(a,b,j);
            }
        }
        for(int j=2;1ll*j*j<=a;j++)
        {
            if(a%j==0)
            {
                p[++tot]=j;
                fenjie(a,b,tot);
            }
        }
        if(a>1)
        {
            p[++tot]=a;
            fenjie(a,b,tot);
        }
    }
    long long sum=1;
    for(int i=1;i<=tot;i++)
    {
        a[i]=mod[i];
        sum*=a[i];
        b[i]=val[i];
    }
    long long ans=0;
    for(int i=1;i<=tot;i++)
    {
        long long x,y,m=sum/a[i];
        exgcd(m,a[i],x,y);
        ans+=(__int128)m*b[i]*x%sum;
        ans%=sum;
    }
    long long k=(ans%sum+sum)%sum;
    for(long long i=1;i<=n;i++)
    {
        long long b=c[i],a=n+1-i;
        if(k%a!=b%a)
        {
            printf("NIE");
            return 0;
        }
    }
    if(k==0)
    {
        k=sum;
    }
    printf("%lld",k);
    return 0;
}
